/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Process an image and a text prompt, generating text from the combined inputs.
 * @param {ImagePipelineInputs} images The image(s) to process.
 * @param {string|string[]} texts The text prompt(s) to condition generation on. When multiple images are provided, each image is paired with the corresponding prompt (cycling through prompts if fewer are given than images).
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using an `AutoModelForImageTextToText`. This pipeline accepts an
 * image and a text prompt and generates text from the combined inputs. It can be used for
 * visual question answering, image captioning with guided prompts, scene description, and more.
 *
 * **Example:** Answer a visual question about an image w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(url, 'What animals are in this image?');
 * // [{ generated_text: 'Two cats are resting on a couch.' }]
 * ```
 *
 * **Example:** Process multiple image-prompt pairs in a single batched call.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const urls = [
 *   'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg',
 *   'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/tiger.jpg',
 * ];
 * const output = await pipe(urls, ['Describe the scene.', 'What animal is shown?']);
 * // [
 * //   [{ generated_text: 'Two cats are resting on a couch.' }],
 * //   [{ generated_text: 'The image shows a tiger.' }],
 * // ]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, texts, generate_kwargs = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);
        const preparedTexts = Array.isArray(texts) ? texts : [texts];

        const toReturn = [];
        for (let i = 0; i < preparedImages.length; i++) {
            const image = preparedImages[i];
            const text = preparedTexts[Math.min(i, preparedTexts.length - 1)];

            const { pixel_values } = await this.processor([image]);
            const text_inputs = this.tokenizer(text, {
                padding: true,
                truncation: true,
            });

            const output = await this.model.generate({
                ...text_inputs,
                pixel_values,
                ...generate_kwargs,
            });

            const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output), {
                skip_special_tokens: true,
            }).map(x => ({ generated_text: x.trim() }));

            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}

